def hash_password(password):
    """Simple password hashing (use bcrypt in production)."""
    import hashlib
    return hashlib.sha256(password.encode()).hexdigest()


def verify_password(password, hashed):
    """Verify password against hash."""
    return hash_password(password) == hashed


def login_required(f):
    """Decorator to require authentication for web routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            return redirect(url_for('login'))
        username = session.get('username')
        if username not in USERS:
            session.clear()
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def api_key_required(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key') or request.args.get('api_key')
        if not api_key or api_key not in API_KEYS:
            return jsonify({'error': 'Invalid or missing API key'}), 401
        request.api_user = API_KEYS[api_key]
        return f(*args, **kwargs)
    return decorated_function


# ==================== Web Routes ====================

@app.route('/')
def index():
    if session.get('authenticated'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))


@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE, error=None, message=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '').strip()
    enable_mfa = request.form.get('enable_mfa') == 'on'

    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required.', message=None)

    if username in USERS:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists.', message=None)

    if len(password) < 6:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 6 characters.', message=None)

    user = {
        'username': username,
        'password_hash': hash_password(password),
        'mfa_enabled': False,
        'mfa_secret': None,
        'api_key': None,
        'created_at': datetime.utcnow().isoformat()
    }

    USERS[username] = user

    if enable_mfa:
        # Generate MFA secret but require confirmation
        mfa_secret = pyotp.random_base32()
        USERS[username]['mfa_secret'] = mfa_secret
        USERS[username]['mfa_enabled'] = True

    message = 'Registration successful!'
    if enable_mfa:
        message += ' MFA has been enabled. Please login and set up your authenticator app.'

    return render_template_string(REGISTER_TEMPLATE, error=None, message=message)


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        message = request.args.get('message')
        return render_template_string(LOGIN_TEMPLATE, error=None, message=message)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '').strip()

    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required.', message=None)

    user = USERS.get(username)
    if not user or not verify_password(password, user['password_hash']):
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password.', message=None)

    # Password verified. Check if MFA is enabled.
    if user['mfa_enabled'] and user['mfa_secret']:
        # Store pending authentication in session
        session['mfa_pending'] = True
        session['mfa_username'] = username
        session['authenticated'] = False
        return redirect(url_for('verify_mfa'))
    else:
        # No MFA - grant access immediately
        session['authenticated'] = True
        session['username'] = username
        session['login_method'] = 'password'
        session['mfa_pending'] = False
        return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if not session.get('mfa_pending'):
        return redirect(url_for('login'))

    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, error=None)

    otp = request.form.get('otp', '').strip()
    username = session.get('mfa_username')

    if not username or username not in USERS:
        session.clear()
        return redirect(url_for('login'))

    user = USERS[username]
    totp = pyotp.TOTP(user['mfa_secret'])

    if totp.verify(otp, valid_window=1):
        # MFA verified - grant access
        session['authenticated'] = True
        session['username'] = username
        session['login_method'] = 'password+mfa'
        session['mfa_pending'] = False
        session.pop('mfa_username', None)
        return redirect(url_for('dashboard'))
    else:
        return render_template_string(MFA_TEMPLATE, error='Invalid OTP. Please try again.')


@app.route('/dashboard')
@login_required
def dashboard():
    username = session['username']
    user = USERS[username]
    message = request.args.get('message')

    mfa_secret = session.pop('show_mfa_secret', None)
    provisioning_uri = None
    if mfa_secret:
        totp = pyotp.TOTP(mfa_secret)
        provisioning_uri = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')

    return render_template_string(
        DASHBOARD_TEMPLATE,
        username=username,
        mfa_enabled=user['mfa_enabled'],
        login_method=session.get('login_method', 'unknown'),
        api_key=user.get('api_key'),
        mfa_secret=mfa_secret,
        provisioning_uri=provisioning_uri,
        message=message
    )


@app.route('/enable-mfa', methods=['POST'])
@login_required
def enable_mfa():
    username = session['username']
    user = USERS[username]

    if user['mfa_enabled']:
        return redirect(url_for('dashboard', message='MFA is already enabled.'))

    # Generate new MFA secret
    mfa_secret = pyotp.random_base32()
    user['mfa_secret'] = mfa_secret
    session['show_mfa_secret'] = mfa_secret
    session['pending_mfa_secret'] = mfa_secret

    return redirect(url_for('dashboard'))


@app.route('/confirm-mfa', methods=['POST'])
@login_required
def confirm_mfa():
    username = session['username']
    user = USERS[username]
    otp = request.form.get('otp', '').strip()

    mfa_secret = user.get('mfa_secret') or session.get('pending_mfa_secret')
    if not mfa_secret:
        return redirect(url_for('dashboard', message='No MFA setup in progress.'))

    totp = pyotp.TOTP(mfa_secret)
    if totp.verify(otp, valid_window=1):
        user['mfa_enabled'] = True
        user['mfa_secret'] = mfa_secret
        session.pop('pending_mfa_secret', None)
        return redirect(url_for('dashboard', message='MFA enabled successfully!'))
    else:
        session['show_mfa_secret'] = mfa_secret
        return redirect(url_for('dashboard', message='Invalid OTP. Please try again.'))


@app.route('/disable-mfa', methods=['POST'])
@login_required
def disable_mfa():
    username = session['username']
    user = USERS[username]
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    return redirect(url_for('dashboard', message='MFA disabled successfully.'))


@app.route('/generate-api-key', methods=['POST'])
@login_required
def generate_api_key():
    username = session['username']
    user = USERS[username]

    # Remove old API key if exists
    if user.get('api_key') and user['api_key'] in API_KEYS:
        del API_KEYS[user['api_key']]

    # Generate new API key
    api_key = secrets.token_hex(32)
    user['api_key'] = api_key
    API_KEYS[api_key] = username

    return redirect